  #new-tab {
    height: 28px;
    padding: 0 10px;
    border-radius: 5px;
    border: 1px solid #444;
    background: #333;
    color: #ddd;
    cursor: pointer;
    font-size: 13px;
    display: flex;
    align-items: center;
