  .tab {
    padding: 7px 16px;
    font-size: 12px;
    color: #999;
    cursor: pointer;
    border-right: 1px solid #333;
    background: transparent;
    white-space: nowrap;
    display: flex;
    align-items: center;
    gap: 6px;
    transition: background 0.12s, color 0.12s;
    flex-shrink: 0;
  }
  .tab:hover { background: #2a2a2a; color: #ccc; }
  .tab.active { background: #2d2d2d; color: #e95420; border-bottom: 2px solid #e95420; }
  .tab .tab-close {
    width: 16px; height: 16px;
    border-radius: 50%;
    border: none;
    background: transparent;
    color: #888;
    font-size: 12px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    line-height: 1;
  }
  .tab .tab-close:hover { background: #555; color: #fff; }
  #editor {
    flex: 1;
    background: #1e1e1e;
    color: #d4d4d4;
    border: none;
    padding: 12px;
    font-family: 'Ubuntu Mono', 'Consolas', 'Courier New', monospace;
    font-size: 14px;
    line-height: 1.5;
    resize: none;
    outline: none;
    overflow-y: auto;
  }
  #editor::placeholder { color: #555; }

  /* Scrollbar */
  ::-webkit-scrollbar { width: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: #444; border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: #555; }
</style>
</head>
