  <!-- Windows -->
  <!-- Files Window -->
  <div id="files-window" class="app-window">
    <div class="win-titlebar" data-drag="files-window">
      <span class="win-title">Files</span>
      <button class="win-close" data-close="files-window">✕</button>
    </div>
    <div class="files-toolbar">
      <button id="files-up">↑</button>
      <span id="files-path">/</span>
    </div>
    <div class="files-body" id="files-body"></div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="app-window">
    <div class="win-titlebar" data-drag="notepad-window">
      <span class="win-title">Text Editor</span>
      <button class="win-close" data-close="notepad-window">✕</button>
    </div>
    <div class="notepad-toolbar">
      <button id="new-tab">＋ New Tab</button>
    </div>
