<script>
(function() {
  // ===== Clock =====
  function updateClock() {
    const now = new Date();
    const opts = { weekday: 'short', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' };
    document.getElementById('topbar-clock').textContent = now.toLocaleDateString('en-US', opts);
  }
  updateClock();
  setInterval(updateClock, 30000);

  // ===== File System Data =====
  const fileSystem = {
    '/': { type: 'dir', children: ['bin', 'etc', 'home', 'usr', 'var'] },
    '/bin': { type: 'dir', children: ['bash', 'ls', 'cat', 'cp', 'mv', 'rm'] },
    '/etc': { type: 'dir', children: ['passwd', 'hostname', 'fstab', 'ssh'] },
    '/etc/ssh': { type: 'dir', children: ['sshd_config', 'ssh_config'] },
    '/home': { type: 'dir', children: ['user'] },
    '/home/user': { type: 'dir', children: ['Documents', 'Downloads', 'Pictures', '.bashrc', '.profile'] },
    '/home/user/Documents': { type: 'dir', children: ['readme.txt', 'notes.md'] },
    '/home/user/Downloads': { type: 'dir', children: ['archive.tar.gz', 'setup.deb'] },
    '/home/user/Pictures': { type: 'dir', children: ['wallpaper.png', 'screenshot.png'] },
    '/usr': { type: 'dir', children: ['bin', 'lib', 'share'] },
    '/usr/bin': { type: 'dir', children: ['python3', 'gcc', 'git', 'vim'] },
    '/usr/lib': { type: 'dir', children: ['libc.so', 'libssl.so'] },
    '/usr/share': { type: 'dir', children: ['doc', 'man', 'locale'] },
    '/var': { type: 'dir', children: ['log', 'tmp', 'cache'] },
    '/var/log': { type: 'dir', children: ['syslog', 'auth.log'] },
    '/var/tmp': { type: 'dir', children: [] },
    '/var/cache': { type: 'dir', children: ['apt'] },
  };

  // Fake file metadata
  const fileMeta = {
    'bash': { type: 'file', icon: '📄' },
    'ls': { type: 'file', icon: '📄' },
    'cat': { type: 'file', icon: '📄' },
    'cp': { type: 'file', icon: '📄' },
    'mv': { type: 'file', icon: '📄' },
    'rm': { type: 'file', icon: '📄' },
    'passwd': { type: 'file', icon: '📄' },
    'hostname': { type: 'file', icon: '📄' },
    'fstab': { type: 'file', icon: '📄' },
    'sshd_config': { type: 'file', icon: '📄' },
    'ssh_config': { type: 'file', icon: '📄' },
    '.bashrc': { type: 'file', icon: '📄' },
    '.profile': { type: 'file', icon: '📄' },
    'readme.txt': { type: 'file', icon: '📄' },
    'notes.md': { type: 'file', icon: '📄' },
    'archive.tar.gz': { type: 'file', icon: '📦' },
    'setup.deb': { type: 'file', icon: '📦' },
    'wallpaper.png': { type: 'file', icon: '🖼️' },
    'screenshot.png': { type: 'file', icon: '🖼️' },
    'python3': { type: 'file', icon: '📄' },
    'gcc': { type: 'file', icon: '📄' },
    'git': { type: 'file', icon: '📄' },
    'vim': { type: 'file', icon: '📄' },
    'libc.so': { type: 'file', icon: '📄' },
    'libssl.so': { type: 'file', icon: '📄' },
    'syslog': { type: 'file', icon: '📄' },
    'auth.log': { type: 'file', icon: '📄' },
  };

  let currentPath = '/';

  function getDir(path) {
    return fileSystem[path];
  }

  function isDir(path) {
    return fileSystem[path] && fileSystem[path].type === 'dir';
  }

  function isFile(name) {
    return !isDir(currentPath + '/' + name);
  }

  function renderFiles() {
    const body = document.getElementById('files-body');
    const pathEl = document.getElementById('files-path');
    pathEl.textContent = currentPath;
    body.innerHTML = '';

    const dir = getDir(currentPath);
    if (!dir) return;

    // Sort: directories first, then files
    const sorted = [...dir.children].sort((a, b) => {
      const aIsDir = isDir(currentPath + '/' + a);
      const bIsDir = isDir(currentPath + '/' + b);
      if (aIsDir && !bIsDir) return -1;
      if (!aIsDir && bIsDir) return 1;
      return a.localeCompare(b);
    });

    sorted.forEach(name => {
      const fullPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
      const isFolder = isDir(fullPath);
      const meta = fileMeta[name];
      const icon = isFolder ? '📁' : (meta ? meta.icon : '📄');

      const item = document.createElement('div');
      item.className = 'fs-item ' + (isFolder ? 'folder' : 'file');
      item.innerHTML = `<span class="fs-icon">${icon}</span><span class="fs-name">${name}</span>`;

      item.addEventListener('dblclick', function(e) {
        e.preventDefault();
        if (isFolder) {
          currentPath = fullPath;
          renderFiles();
        }
      });

      body.appendChild(item);
    });
  }

  document.getElementById('files-up').addEventListener('click', function() {
    if (currentPath !== '/') {
      currentPath = currentPath.substring(0, currentPath.lastIndexOf('/')) || '/';
      renderFiles();
    }
  });

  // ===== Notepad App =====
  const STORAGE_KEY = 'notepad-tabs';

  function loadTabs() {
    try {
      const data = localStorage.getItem(STORAGE_KEY);
      if (data) return JSON.parse(data);
    } catch(e) {}
    return [];
  }

  function saveTabs() {
    const tabs = getTabsData();
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
  }

  let tabs = loadTabs();
  let activeTabId = null;

  function generateId() {
    return 'tab-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);
  }

  function ensureTabs() {
    if (tabs.length === 0) {
      const id = generateId();
      tabs.push({ id: id, name: 'Untitled', content: '' });
      activeTabId = id;
      saveTabs();
    }
    if (!activeTabId || !tabs.find(t => t.id === activeTabId)) {
      activeTabId = tabs[0].id;
    }
  }

  function getTabsData() {
    const editor = document.getElementById('editor');
    const currentContent = editor ? editor.value : '';
    const activeTab = tabs.find(t => t.id === activeTabId);
    if (activeTab) {
      activeTab.content = currentContent;
    }
    return tabs;
  }

  function renderTabs() {
    ensureTabs();
    const tabsContainer = document.getElementById('tabs');
    tabsContainer.innerHTML = '';

    tabs.forEach(tab => {
      const tabEl = document.createElement('div');
      tabEl.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
      tabEl.innerHTML = `<span>${tab.name}</span><button class="tab-close" data-tab-id="${tab.id}">✕</button>`;

      tabEl.querySelector('.tab').addEventListener('click', function(e) {
        if (e.target.classList.contains('tab-close')) return;
        switchTab(tab.id);
      });

      tabEl.querySelector('.tab-close').addEventListener('click', function(e) {
        e.stopPropagation();
        closeTab(tab.id);
      });

      tabsContainer.appendChild(tabEl);
    });

    // Update editor
    const activeTab = tabs.find(t => t.id === activeTabId);
    if (activeTab) {
      document.getElementById('editor').value = activeTab.content;
    }
  }

  function switchTab(id) {
    // Save current
    getTabsData();
    activeTabId = id;
    renderTabs();
    saveTabs();
  }

  function closeTab(id) {
    const idx = tabs.findIndex(t => t.id === id);
    if (idx === -1) return;
    tabs.splice(idx, 1);
    if (tabs.length === 0) {
      const newId = generateId();
      tabs.push({ id: newId, name: 'Untitled', content: '' });
      activeTabId = newId;
    } else if (activeTabId === id) {
      activeTabId = tabs[Math.min(idx, tabs.length - 1)].id;
    }
    renderTabs();
    saveTabs();
  }

  document.getElementById('new-tab').addEventListener('click', function() {
    getTabsData();
    const id = generateId();
    const num = tabs.length + 1;
    tabs.push({ id: id, name: 'Untitled ' + num, content: '' });
    activeTabId = id;
    renderTabs();
    saveTabs();
  });

  document.getElementById('editor').addEventListener('input', function() {
    const activeTab = tabs.find(t => t.id === activeTabId);
    if (activeTab) {
      activeTab.content = this.value;
    }
    saveTabs();
  });

  // ===== Window Management =====
  const windows = {
    'files-window': { el: null, visible: false },
    'notepad-window': { el: null, visible: false },
  };

  function toggleWindow(id) {
    const el = document.getElementById(id);
    if (!el) return;
    if (el.classList.contains('visible')) {
      el.classList.remove('visible');
      windows[id].visible = false;
    } else {
      el.classList.add('visible');
      windows[id].visible = true;
      if (id === 'files-window') renderFiles();
      if (id === 'notepad-window') {
        getTabsData();
        renderTabs();
      }
    }
    updateDockActive();
  }

  function updateDockActive() {
    document.getElementById('open-files').classList.toggle('active', windows['files-window'].visible);
    document.getElementById('open-notepad').classList.toggle('active', windows['notepad-window'].visible);
  }

  document.getElementById('open-files').addEventListener('click', function() {
    toggleWindow('files-window');
    document.getElementById('topbar-app-name').textContent = 'Files';
  });

  document.getElementById('open-notepad').addEventListener('click', function() {
    toggleWindow('notepad-window');
    document.getElementById('topbar-app-name').textContent = 'Text Editor';
  });

  document.querySelectorAll('.win-close').forEach(btn => {
    btn.addEventListener('click', function() {
      const winId = this.getAttribute('data-close');
      toggleWindow(winId);
    });
  });

  // ===== Draggable Windows =====
  document.querySelectorAll('.win-titlebar[data-drag]').forEach(titlebar => {
    let isDragging = false;
    let startX, startY, origLeft, origTop;

    titlebar.addEventListener('mousedown', function(e) {
      if (e.target.classList.contains('win-close')) return;
      isDragging = true;
      const winId = this.getAttribute('data-drag');
      const win = document.getElementById(winId);
      startX = e.clientX;
      startY = e.clientY;
      origLeft = win.offsetLeft;
      origTop = win.offsetTop;
      win.style.zIndex = 60;
      e.preventDefault();
    });

    document.addEventListener('mousemove', function(e) {
      if (!isDragging) return;
      const winId = titlebar.getAttribute('data-drag');
      const win = document.getElementById(winId);
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      win.style.left = (origLeft + dx) + 'px';
      win.style.top = (origTop + dy) + 'px';
    });

    document.addEventListener('mouseup', function() {
      isDragging = false;
    });
  });

  // ===== Init =====
  renderFiles();
  ensureTabs();
  renderTabs();
})();
</script>
</body>
</html>
